from sklearn.ensemble import RandomForestClassifier, ExtraTreesClassifier
from sklearn.svm import SVC
from sklearn.linear_model import LogisticRegression
from sklearn.neighbors import KNeighborsClassifier
from sklearn.neural_network import MLPClassifier
from sklearn.metrics import accuracy_score
import numpy as np

def solve(X_train, y_train, X_val, y_val):
    # Try different models and their hyperparameters
    models = {
        'RandomForest': RandomForestClassifier(),
        'ExtraTrees': ExtraTreesClassifier(),
        'SVM': SVC(),
        'LogisticRegression': LogisticRegression(max_iter=200),
        'KNeighbors': KNeighborsClassifier()
    }

    best_accuracy = 0.9370  # Current best accuracy from iteration 31

    for model_name, model in models.items():
        if model_name == 'SVM':
            model.kernel = 'linear'  # Adjust SVM kernel for better performance

        if model_name == 'LogisticRegression':
            model.solver = 'liblinear'  # Faster solver for Logistic Regression

        if model_name == 'KNeighbors':
            model.n_neighbors = 3  # Small k for better local behavior

        if model_name == 'RandomForest':
            model.max_depth = 10  # Limit depth to prevent overfitting

        if model_name == 'ExtraTrees':
            model.max_depth = 10  # Limit depth to prevent overfitting

        if model_name == 'MLPClassifier':
            model.hidden_layer_sizes = (64, 32)  # Adjust network architecture

        model.fit(X_train, y_train)
        predictions = model.predict(X_val)
        accuracy = accuracy_score(y_val, predictions)

        if accuracy > best_accuracy:
            best_accuracy = accuracy

    return predictions
